<script setup lang="ts">import{computed,ref}from'vue';import{useSkillsStore}from'../store';import MediaCard from'../components/MediaCard.vue';const store=useSkillsStore(),search=ref(''),domain=ref('All');const domains=computed(()=>['All',...new Set(store.programmes.map(x=>x.domain))]);const filtered=computed(()=>store.programmes.filter(x=>(domain.value==='All'||x.domain===domain.value)&&`${x.title} ${x.provider}`.toLowerCase().includes(search.value.toLowerCase())))</script>
<template><main><section class="hero"><div><span>Skills intelligence for Europe</span><h1>Build capability for what comes next.</h1><p>Map critical roles to verified learning pathways across Brussels and the EU.</p><button @click="store.toggleSaved(1)">Save recommended pathway</button><button class="ghost">View skills report</button></div></section><section class="controls"><div><h2>Opportunity map</h2><p>Role-aligned programmes for regulated and transitioning industries.</p></div><input v-model="search" aria-label="Search pathways" placeholder="Search skills or providers"/><select v-model="domain" aria-label="Filter by domain"><option v-for="item in domains" :key="item">{{item}}</option></select></section><TransitionGroup v-if="filtered.length" name="list" tag="section" class="media-grid"><MediaCard v-for="item in filtered" :key="item.id" :programme="item"/></TransitionGroup><div v-else class="empty">No pathways match this search.</div></main></template>
